#include <algorithm>

using namespace std;

bool isPalindrome(const string& s) {
    string s_rev = s;
    reverse(s_rev.begin(), s_rev.end());
    return s == s_rev;
}

bool isSpecial(const string& s) {
    unordered_map<char, int> count;
    for (char c : s) {
        count[c]++;
    }
    for (auto& pair : count) {
        if (pair.second != (pair.first - '0')) {
            return false;
        }
    }
    return true;
}

long long solve(long long n) {
    long long result = n + 1;
    while (true) {
        string s = to_string(result);
        if (isPalindrome(s) && isSpecial(s)) {
            return result;
        }
        result++;
    }
}

